#include <stdio.h>
#include <string.h>
#define MAX 100

int min(int a, int b) { return a < b ? a : b; }

int bfs(int graph[MAX][MAX], int V, int s, int t, int parent[]) {
  int visited[MAX] = {0};
  int queue[MAX], front = 0, rear = 0;
  queue[rear++] = s; visited[s] = 1; parent[s] = -1;
  while (front < rear) {
    int u = queue[front++];
    for (int v = 0; v < V; v++) {
      if (!visited[v] && graph[u][v] > 0) {
        queue[rear++] = v; parent[v] = u; visited[v] = 1;
        if (v == t) return 1;
      }
    }
  }
  return 0;
}

int fordFulkerson(int graph[MAX][MAX], int V, int s, int t) {
  int residual[MAX][MAX];
  memcpy(residual, graph, sizeof(residual));
  int parent[MAX], max_flow = 0;
  while (bfs(residual, V, s, t, parent)) {
    int path_flow = 1e9;
    for (int v = t; v != s; v = parent[v]) {
      int u = parent[v];
      path_flow = min(path_flow, residual[u][v]);
    }
    for (int v = t; v != s; v = parent[v]) {
      int u = parent[v];
      residual[u][v] -= path_flow; residual[v][u] += path_flow;
    }
    max_flow += path_flow;
  }
  return max_flow;
}

int main() {
  int V = 6;
  int graph[MAX][MAX] = {
    {0, 16, 13, 0, 0, 0},
    {0, 0, 10, 12, 0, 0},
    {0, 4, 0, 0, 14, 0},
    {0, 0, 9, 0, 0, 20},
    {0, 0, 0, 7, 0, 4},
    {0, 0, 0, 0, 0, 0}
