using System;
using System.Collections.Generic;

class Graph {
  private int V;
  private int[,] graph;
  public Graph(int v) { V = v; graph = new int[v, v]; }
  public void AddEdge(int u, int v, int w) { graph[u, v] = w; }
  private bool BFS(int[,] residual, int s, int t, int[] parent) {
    bool[] visited = new bool[V];
    Queue<int> q = new Queue<int>();
    q.Enqueue(s); visited[s] = true; parent[s] = -1;
    while (q.Count > 0) {
      int u = q.Dequeue();
      for (int v = 0; v < V; v++) {
        if (!visited[v] && residual[u, v] > 0) {
          q.Enqueue(v); parent[v] = u; visited[v] = true;
          if (v == t) return true;
        }
      }
    }
    return false;
  }
  public int FordFulkerson(int s, int t) {
    int[,] residual = new int[V, V];
    Array.Copy(graph, residual, graph.Length);
    int[] parent = new int[V];
    int max_flow = 0;
    while (BFS(residual, s, t, parent)) {
      int path_flow = int.MaxValue;
      for (int v = t; v != s; v = parent[v]) {
        int u = parent[v];
        path_flow = Math.Min(path_flow, residual[u, v]);
      }
      for (int v = t; v != s; v = parent[v]) {
        int u = parent[v];
        residual[u, v] -= path_flow; residual[v, u] += path_flow;
      }
      max_flow += path_flow;
    }
    return max_flow;
  }
}

